#!/usr/bin/env node
/**
 * i18n validation gate for the docs site.
 *
 * The site is Fumadocs i18n (en/zh/ja/ko, en unprefixed, `parser:'dot'` →
 * `page.zh.mdx`). Every English page should have a translated sibling in each
 * non-default locale, EXCEPT sections listed in `EN_ONLY_SECTIONS` (the
 * auto-generated TypeDoc `api/` reference is deliberately English-only — it is
 * pure code reference, regenerated by `generate:api`, and reachable in every
 * locale via Fumadocs `fallbackLanguage`).
 *
 * Checks (ERROR fails the build; WARN is advisory):
 *   E1  missing locale sibling for a translatable EN page
 *   E2  locale file byte-identical to its EN source (untranslated stub)
 *   W1  locale file contains no script characters for that locale (likely
 *       untranslated copy) — zh: Han, ja: Kana/Han, ko: Hangul
 *   W2  locale file missing frontmatter `title` or `description`
 *   W3  internal absolute doc link in a non-EN page is not locale-prefixed
 *       (would bounce the reader back to English) — Task 4 requirement
 *
 * Wired via `check:i18n`. Run: `pnpm --filter @anvilkit/docs-site check:i18n`.
 */
import { readdirSync, readFileSync } from "node:fs";
import { dirname, join, relative } from "node:path";
import { fileURLToPath } from "node:url";

const HERE = dirname(fileURLToPath(import.meta.url));
const DOCS_ROOT = join(HERE, "..", "content", "docs");
const LOCALES = ["zh", "ja", "ko"];
const EN_ONLY_SECTIONS = new Set(["api"]);
// Absolute-link first segments that are valid without a locale prefix: app
// routes that are not localized docs, plus the EN-only sections.
const UNPREFIXED_OK = new Set(["playground", "api", "registry"]);

const SCRIPT_RE = {
	zh: /[一-鿿]/, // Han
	ja: /[぀-ヿ一-鿿]/, // Kana or Han
	ko: /[가-힯]/, // Hangul
};

const errors = [];
const warns = [];
const err = (m) => errors.push(m);
const warn = (m) => warns.push(m);

function walk(dir, acc = []) {
	for (const e of readdirSync(dir, { withFileTypes: true })) {
		const p = join(dir, e.name);
		if (e.isDirectory()) walk(p, acc);
		else acc.push(p);
	}
	return acc;
}

const isDoc = (f) => f.endsWith(".mdx") || f.endsWith(".md");
const localeOf = (f) => f.match(/\.(zh|ja|ko)\.(?:mdx|md)$/)?.[1] ?? "en";
const sectionOf = (f) => relative(DOCS_ROOT, f).split("/")[0];
const rel = (f) => relative(DOCS_ROOT, f);

function stripFrontmatter(src) {
	const m = src.match(/^---\n[\s\S]*?\n---\n?/);
	return m ? src.slice(m[0].length) : src;
}
function frontmatter(src) {
	const m = src.match(/^---\n([\s\S]*?)\n---/);
	return m ? m[1] : "";
}

// Strip code (fenced + inline) so link/script checks ignore code samples.
function stripCode(body) {
	return body.replace(/```[\s\S]*?```/g, "").replace(/`[^`]*`/g, "");
}

const allDocs = walk(DOCS_ROOT).filter(isDoc);

// Map base (locale-agnostic) → { en, zh, ja, ko } absolute paths.
const groups = new Map();
for (const f of allDocs) {
	const base = f.replace(/\.(zh|ja|ko)\.(mdx|md)$/, ".$2");
	const g = groups.get(base) ?? {};
	g[localeOf(f)] = f;
	groups.set(base, g);
}

let translatable = 0;
for (const [base, g] of groups) {
	if (!g.en) continue; // orphan translation w/o EN source — ignore
	const section = sectionOf(g.en);
	if (EN_ONLY_SECTIONS.has(section)) continue;
	translatable++;

	const enSrc = readFileSync(g.en, "utf8");
	for (const loc of LOCALES) {
		const lf = g[loc];
		if (!lf) {
			err(`E1 missing ${loc} translation for ${rel(g.en)}`);
			continue;
		}
		const locSrc = readFileSync(lf, "utf8");
		if (locSrc === enSrc) {
			err(
				`E2 ${rel(lf)} is byte-identical to its EN source (untranslated stub)`,
			);
			continue;
		}
		const fm = frontmatter(locSrc);
		if (!/(^|\n)title:/.test(fm))
			warn(`W2 ${rel(lf)} missing frontmatter title`);
		if (!/(^|\n)description:/.test(fm))
			warn(`W2 ${rel(lf)} missing frontmatter description`);

		const body = stripCode(stripFrontmatter(locSrc));
		if (!SCRIPT_RE[loc].test(body)) {
			warn(
				`W1 ${rel(lf)} contains no ${loc} script characters (likely untranslated)`,
			);
		}

		// W3 — internal absolute doc links must stay in-locale.
		const links = body.matchAll(/\]\((\/[^)\s#?]*)/g);
		for (const [, href] of links) {
			const seg = href.split("/").filter(Boolean)[0];
			if (!seg) continue; // bare "/" home
			if (LOCALES.includes(seg)) continue; // already locale-prefixed
			if (UNPREFIXED_OK.has(seg)) continue; // app route / en-only section
			if (/\.(png|jpe?g|svg|gif|webp|pdf|json|ico)$/i.test(href)) continue; // asset
			warn(
				`W3 ${rel(lf)} links to "${href}" without a /${loc} prefix (reader leaves ${loc})`,
			);
		}
	}
}

// ---------------------------------------------------------------------------
console.log(
	`[check-i18n] ${translatable} translatable EN pages × ${LOCALES.length} locales checked (api/ is intentionally EN-only).`,
);
for (const w of warns) console.warn(`  WARN  ${w}`);
for (const e of errors) console.error(`  ERROR ${e}`);
console.log(
	`[check-i18n] ${errors.length} error(s), ${warns.length} warning(s).`,
);
if (errors.length > 0) process.exit(1);
